set -euo pipefail
source "$(dirname "$0")/../common/test_helpers.sh"

log_info "=== E2E: Dep Subcommands ==="

# Setup
setup_test_db

# Create test issues
ID1=$(br create "Parent issue" --silent 2>&1)
ID2=$(br create "Child issue" --silent 2>&1)
ID3=$(br create "Grandchild issue" --silent 2>&1)
log_debug "Created: $ID1, $ID2, $ID3"

# Test 1: dep add
log_step "Testing dep add"
ADD_OUTPUT=$(br dep add "$ID1" "$ID2" 2>&1)
assert_contains "$ADD_OUTPUT" "Added" "Should confirm dependency added"
log_pass "dep add works"

# Test 2: dep add second level
log_step "Testing dep add second level"
br dep add "$ID2" "$ID3" > /dev/null 2>&1
log_pass "dep add second level works"

# Test 3: dep list
log_step "Testing dep list"
LIST_OUTPUT=$(br dep list "$ID1" 2>&1)
assert_contains "$LIST_OUTPUT" "$ID2" "Should show dependent"
log_pass "dep list works"

# Test 4: dep tree
log_step "Testing dep tree"
TREE_OUTPUT=$(br dep tree "$ID1" 2>&1)
assert_contains "$TREE_OUTPUT" "$ID1" "Should show root"
assert_contains "$TREE_OUTPUT" "$ID2" "Should show child"
log_pass "dep tree works"

# Test 5: dep cycles (should be none)
log_step "Testing dep cycles (no cycles)"
CYCLES_OUTPUT=$(br dep cycles 2>&1)
assert_contains "$CYCLES_OUTPUT" "No" "Should have no cycles"
log_pass "dep cycles clean"

# Test 6: Create and detect cycle
log_step "Testing cycle detection"
br dep add "$ID3" "$ID1" > /dev/null 2>&1 || true  # This creates a cycle
CYCLES_OUTPUT=$(br dep cycles 2>&1)
assert_contains "$CYCLES_OUTPUT" "cycle" "Should detect cycle"
log_pass "cycle detection works"

# Test 7: dep rm
log_step "Testing dep rm"
br dep rm "$ID3" "$ID1" > /dev/null 2>&1
CLEAN_CYCLES=$(br dep cycles 2>&1)
log_pass "dep rm works"

# Test 8: JSON output
log_step "Testing JSON output"
JSON_LIST=$(br dep list "$ID1" --json 2>&1)
echo "$JSON_LIST" | jq . > /dev/null
log_pass "JSON output works"

# Test 9: Rich mode tree
log_step "Testing rich mode tree"
RICH_TREE=$(script -q /dev/null br dep tree "$ID1" 2>&1 || true)
log_pass "Rich mode tree renders"

